import{_ as i,C as g,o as a,c as h,a5 as r,b as n,w as e,a as s,E as o,a4 as d}from"./chunks/framework.gGRxziV4.js";const c=JSON.parse('{"title":"Harness 即操作系统","description":"","frontmatter":{},"headers":[],"relativePath":"01-Harness工程核心原则/04-Harness即操作系统.md","filePath":"01-Harness工程核心原则/04-Harness即操作系统.md","lastUpdated":1774181700000}'),A={name:"01-Harness工程核心原则/04-Harness即操作系统.md"};function E(p,t,f,b,u,x){const l=g("Mermaid");return a(),h("div",null,[t[2]||(t[2]=r('<h1 id="harness-即操作系统" tabindex="-1">Harness 即操作系统 <a class="header-anchor" href="#harness-即操作系统" aria-label="Permalink to &quot;Harness 即操作系统&quot;">​</a></h1><p><strong>Harness Engineering 核心原则 · 第四章</strong></p><blockquote><p>这个时代的操作系统是什么？是 Agent Harness。</p></blockquote><p>前三章建立了 Harness 的基本图景：范式转移、感官系统、成本与熵增。本章我们把视角拉到最高——Harness 到底是什么？怎么构建？底层逻辑是什么？</p><p>答案分三层：Harness 是操作系统，但要为废弃而建，而这一切的底层是控制论。</p><hr><h2 id="一、harness-操作系统" tabindex="-1">一、Harness = 操作系统 <a class="header-anchor" href="#一、harness-操作系统" aria-label="Permalink to &quot;一、Harness = 操作系统&quot;">​</a></h2><p>Google DeepMind 工程师 Filip Hráček 提出了一个精妙的比喻。</p><h3 id="静态跑分的错觉" tabindex="-1">静态跑分的错觉 <a class="header-anchor" href="#静态跑分的错觉" aria-label="Permalink to &quot;静态跑分的错觉&quot;">​</a></h3><p>各家顶尖模型在静态跑分上的差距已经缩小到很小了。但这可能是一种错觉——<strong>任务越长越复杂，模型之间真正的差距才会暴露出来。</strong></p><p>你让模型进企业跑一个长线自动化流程：读几百页文档、查代码总结依赖关系、调 API、建工单、汇总报告。跑着跑着它就开始跑偏了，或者完全忘了第一步定好的安全规则。</p><p>排行榜上那点分差，根本测不出这种灾难。</p><h3 id="四大核心功能" tabindex="-1">四大核心功能 <a class="header-anchor" href="#四大核心功能" aria-label="Permalink to &quot;四大核心功能&quot;">​</a></h3><p>Agent Harness 是包裹在 AI 模型外围的基础设施，用来管理长生命周期的任务。它有四大核心功能：</p><table tabindex="0"><thead><tr><th style="text-align:left;">功能</th><th style="text-align:left;">作用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Prompt Presets</strong></td><td style="text-align:left;">模型开始干活前，自动塞好一套规矩</td></tr><tr><td style="text-align:left;"><strong>Tool Call Handling</strong></td><td style="text-align:left;">统一处理 Agent 调用外部工具的逻辑</td></tr><tr><td style="text-align:left;"><strong>Lifecycle Hooks</strong></td><td style="text-align:left;">每执行完一步自动触发检查，不过就拦截打回</td></tr><tr><td style="text-align:left;"><strong>高阶能力</strong></td><td style="text-align:left;">自动规划、文件系统读写、子 Agent 管理</td></tr></tbody></table><p>其中<strong>生命周期钩子</strong>尤其关键——它是提前在流程里埋好的检查站。模型每执行完一步，钩子就自动触发一次检查：输出格式对不对？Token 有没有超限？有没有触发安全红线？如果检查不过，钩子直接拦截打回重来。</p><h3 id="完整的比喻" tabindex="-1">完整的比喻 <a class="header-anchor" href="#完整的比喻" aria-label="Permalink to &quot;完整的比喻&quot;">​</a></h3>',17)),(a(),n(d,null,{default:e(()=>[o(l,{id:"mermaid-94",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E5%A4%A7%E6%A8%A1%E5%9E%8B%5D%20--%3E%7C%E8%AE%A1%E7%AE%97%E8%83%BD%E5%8A%9B%7C%20B%5BHarness%20%E6%93%8D%E4%BD%9C%E7%B3%BB%E7%BB%9F%5D%0A%20%20%20%20B%20--%3E%20C%5B%E6%96%99%E7%90%86%E4%B8%8A%E4%B8%8B%E6%96%87%20%3D%20RAM%20%E7%AE%A1%E7%90%86%5D%0A%20%20%20%20B%20--%3E%20D%5B%E5%BC%80%E6%9C%BA%E5%BC%95%E5%AF%BC%20%3D%20%E5%A1%9E%E5%9F%BA%E7%A1%80%20Prompt%5D%0A%20%20%20%20B%20--%3E%20E%5B%E7%94%9F%E5%91%BD%E5%91%A8%E6%9C%9F%E9%92%A9%E5%AD%90%20%3D%20%E8%87%AA%E5%8A%A8%E6%A3%80%E6%9F%A5%E7%AB%99%5D%0A%20%20%20%20B%20--%3E%20F%5B%E9%A9%B1%E5%8A%A8%E7%A8%8B%E5%BA%8F%20%3D%20%E5%B7%A5%E5%85%B7%E8%B0%83%E7%94%A8%E5%A4%84%E7%90%86%5D%0A%20%20%20%20C%20--%3E%20G%5BAgent%20%E5%BA%94%E7%94%A8%5D%0A%20%20%20%20D%20--%3E%20G%0A%20%20%20%20E%20--%3E%20G%0A%20%20%20%20F%20--%3E%20G%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=r('<blockquote><p>💡 <strong>图解：</strong> Harness 是包裹在大模型外围的 OS——大模型是 CPU，上下文窗口是 RAM，Harness 才是让一切协同运转的操作系统。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">组件</th><th style="text-align:left;">比喻</th><th style="text-align:left;">作用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大模型</strong></td><td style="text-align:left;">CPU</td><td style="text-align:left;">提供原始的计算处理能力</td></tr><tr><td style="text-align:left;"><strong>上下文窗口</strong></td><td style="text-align:left;">RAM（内存条）</td><td style="text-align:left;">容量有限，关掉就没了</td></tr><tr><td style="text-align:left;"><strong>Agent Harness</strong></td><td style="text-align:left;"><strong>操作系统（OS）</strong></td><td style="text-align:left;">料理上下文、处理开机引导、预埋钩子、提供驱动</td></tr><tr><td style="text-align:left;"><strong>Agent 应用</strong></td><td style="text-align:left;">APP</td><td style="text-align:left;">跑在操作系统之上的应用程序</td></tr></tbody></table><p>Harness 就是操作系统。它负责料理上下文、处理开机引导（塞基础提示词）、预埋生命周期钩子、提供标准化的驱动程序（工具调用处理）。</p><h3 id="_2026-年的核心定位" tabindex="-1">2026 年的核心定位 <a class="header-anchor" href="#_2026-年的核心定位" aria-label="Permalink to &quot;2026 年的核心定位&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">不是</th><th style="text-align:left;">而是</th></tr></thead><tbody><tr><td style="text-align:left;">业务代码</td><td style="text-align:left;"><strong>底座</strong></td></tr><tr><td style="text-align:left;">应用</td><td style="text-align:left;"><strong>操作系统</strong></td></tr><tr><td style="text-align:left;">锦上添花</td><td style="text-align:left;"><strong>基础设施</strong></td></tr></tbody></table><p>Harness 弥合了跑分和真实体验之间的鸿沟，释放了模型的潜力，构建了闭环反馈——你改进系统的能力上限，完全取决于你验证输出有多容易。</p><hr><h2 id="二、为废弃而构建" tabindex="-1">二、为废弃而构建 <a class="header-anchor" href="#二、为废弃而构建" aria-label="Permalink to &quot;二、为废弃而构建&quot;">​</a></h2><p>Harness 是操作系统，那该怎么构建它？</p><p>你可能会想：输出格式不对就加一层校验拦截重试，多步规划走偏了就搭一套复杂的状态机强制纠偏。这套思路在传统软件工程里没毛病，但放到 Agent Harness 上——<strong>行不通</strong>。</p><h3 id="苦涩的教训" tabindex="-1">苦涩的教训 <a class="header-anchor" href="#苦涩的教训" aria-label="Permalink to &quot;苦涩的教训&quot;">​</a></h3><p>计算机科学家 Rich Sutton 写过一篇著名的短文叫 <em>&quot;The Bitter Lesson&quot;</em>。核心论点：过去 30 年，凡是<strong>依赖庞大算力的通用方法</strong>，每一次都击败了人类手工编码进去的先验知识。无一例外。</p><p>这堂课正在 Agent 开发领域真实重演。</p><h3 id="顶级团队在疯狂删代码" tabindex="-1">顶级团队在疯狂删代码 <a class="header-anchor" href="#顶级团队在疯狂删代码" aria-label="Permalink to &quot;顶级团队在疯狂删代码&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">团队</th><th style="text-align:left;">动作</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Mistral</strong></td><td style="text-align:left;">6 个月内把 Harness 重构了 5 次</td></tr><tr><td style="text-align:left;"><strong>LangChain</strong></td><td style="text-align:left;">一年内把 Open Deep Research 架构推翻重写了 3 次</td></tr><tr><td style="text-align:left;"><strong>Vercel</strong></td><td style="text-align:left;">直接砍掉了 Agent 80% 的代码，结果执行步骤更少、Token 消耗更低、响应速度更快</td></tr></tbody></table><p>顶级团队不是在加代码，是在<strong>疯狂地删代码</strong>。之前精心设计的&quot;聪明逻辑&quot;，在新模型面前全成了累赘。</p><h3 id="build-to-delete" tabindex="-1">Build to Delete <a class="header-anchor" href="#build-to-delete" aria-label="Permalink to &quot;Build to Delete&quot;">​</a></h3><p>所以 Harness 的构建原则是：<strong>为废弃而构建。</strong></p><p>每当新模型一发布，它必然带来全新的 Agent 构建方式。2024 年还需要复杂管道才能实现的功能，2026 年可能一条 Prompt 就搞定了。所以你的 Harness 架构必须像乐高积木一样松散——允许你随时流畅地撕掉昨天才写好的那段&quot;聪明控制逻辑&quot;。</p><blockquote><p>如果你对控制流做了过度设计，下一次模型更新会直接击穿你的系统。</p></blockquote><h3 id="harness-的真正价值-捕获崩溃数据" tabindex="-1">Harness 的真正价值：捕获崩溃数据 <a class="header-anchor" href="#harness-的真正价值-捕获崩溃数据" aria-label="Permalink to &quot;Harness 的真正价值：捕获崩溃数据&quot;">​</a></h3><p>既然写的 Harness 代码注定要被删，它的价值在哪儿？</p><p>答案是<strong>模型漂移（Model Drift）</strong>。模型在短对话里表现得很好，但在超长任务中会慢慢&quot;缺氧&quot;——忘记开局设定的规则，开始胡言乱语。</p><p>Harness 像飞机黑匣子一样，精确记录模型在第 100 步之后到底是在哪个节点上丧失了遵循指令的能力。这些断点数据可以直接投喂回训练集，反哺到下一轮训练。</p><blockquote><p><strong>The Harness is the dataset.</strong></p></blockquote><p>谁的 Harness 在真实场景里拦截到了更多崩溃轨迹，谁就能提炼出更好的后训练数据集，就有可能训练出更好的模型。</p><p>所以结论很简单：<strong>不要抗拒重构和废弃代码。</strong> 学会张开监控网，记录大模型每一次失控的瞬间——这是用来训练更强模型的宝贵数据集。</p><hr><h2 id="三、控制论-闭环与校准" tabindex="-1">三、控制论：闭环与校准 <a class="header-anchor" href="#三、控制论-闭环与校准" aria-label="Permalink to &quot;三、控制论：闭环与校准&quot;">​</a></h2><p>为什么很多团队一上 Coding Agent，反而更乱了？代码产出多了，但代码库更脏了。PR 合并快了，但架构漂移也快了。</p><p>硅谷工程师 George 的判断是：这不是简单的 AI 写码问题，<strong>这是控制论进入代码生产层</strong>。</p><h3 id="这个模式见过三次" tabindex="-1">这个模式见过三次 <a class="header-anchor" href="#这个模式见过三次" aria-label="Permalink to &quot;这个模式见过三次&quot;">​</a></h3><p>第一次是 18 世纪的蒸汽机调速器。James Watt 发明了离心调速器——一个机械装置感知转速，自动调节阀门。工人的工作从转阀门变成设计调速器。</p><p>第二次是 Google 的 Borg 服务器管理系统。你告诉它系统应该长什么样，它就自动维持那个状态。工程师的工作从手动重启服务变成写清楚系统应该长什么样。</p><p>第三次就是现在，OpenAI 的 Coding Agent。工程师不再写代码，他们设计环境、构建反馈回路，让 Agent 写代码。五个月，100 万行，零行手写。</p><p>Norbert Wiener 在 1948 年给这个模式命名：<strong>控制论（Cybernetics）</strong>。核心就一个词——<strong>闭环</strong>。输出影响输入，系统自己纠偏。</p>',36)),(a(),n(d,null,{default:e(()=>[o(l,{id:"mermaid-333",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%E8%AE%BE%E5%AE%9A%E7%9B%AE%E6%A0%87%2F%E8%A7%84%E8%8C%83%5D%20--%3E%20B%5B%E6%89%A7%E8%A1%8C%E5%99%A8%5D%0A%20%20%20%20B%20--%3E%20C%5B%E7%B3%BB%E7%BB%9F%E8%BE%93%E5%87%BA%5D%0A%20%20%20%20C%20--%3E%20D%5B%E4%BC%A0%E6%84%9F%E5%99%A8%3Cbr%2F%3E%E6%84%9F%E7%9F%A5%E8%BE%93%E5%87%BA%5D%0A%20%20%20%20D%20--%3E%20E%5B%E5%AF%B9%E6%AF%94%E7%9B%AE%E6%A0%87%5D%0A%20%20%20%20E%20--%3E%7C%E5%81%8F%E5%B7%AE%7C%20F%5B%E7%BA%A0%E5%81%8F%2F%E4%BF%AE%E6%AD%A3%5D%0A%20%20%20%20F%20--%3E%20B%0A%20%20%20%20E%20--%3E%7C%E8%BE%BE%E6%A0%87%7C%20G%5B%E7%A8%B3%E5%AE%9A%E7%8A%B6%E6%80%81%5D%0A%20%20%20%20style%20F%20fill%3A%23f96%0A"})]),fallback:e(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r('<blockquote><p>💡 <strong>图解：</strong> 每一次技术跃迁——蒸汽机调速器、Borg、Coding Agent——本质都是在某个层级上第一次成功闭环。</p></blockquote><blockquote><p>每一次技术跃迁，都是在某个层级上第一次成功闭环。</p></blockquote><h3 id="为什么代码库是最后一个被攻克的" tabindex="-1">为什么代码库是最后一个被攻克的？ <a class="header-anchor" href="#为什么代码库是最后一个被攻克的" aria-label="Permalink to &quot;为什么代码库是最后一个被攻克的？&quot;">​</a></h3><p>代码库一直有反馈回路，但只在低层级：编译器检查语法、测试检查行为、Linter 检查风格。这些只能处理可以机械检查的东西。</p><p>更高层的问题从来没有自动化过——这个改动符合系统架构吗？这个抽象随着代码库增长会出问题吗？这些问题没有传感器，也没有执行器，只有人能在这个层级上操作。</p><p><strong>LLM 同时改变了两者</strong>：它能感知架构质量，也能执行架构修改。历史上第一次，反馈回路可以在重要决策发生的地方闭合。</p><h3 id="闭环是必要条件-不是充分条件" tabindex="-1">闭环是必要条件，不是充分条件 <a class="header-anchor" href="#闭环是必要条件-不是充分条件" aria-label="Permalink to &quot;闭环是必要条件，不是充分条件&quot;">​</a></h3><p>Watt 的调速器需要调教。Borg 的控制器需要正确的 spec。接上 Agent 不等于完事儿了——真正的工作是<strong>校准这个回路</strong>，让它知道什么叫&quot;好&quot;。</p><p>工程师脑子里的判断力是隐性知识，通过经验积累，很难言传。Agent 没有 code review、结对编程、口耳相传的渠道。你必须把隐性知识变成<strong>显性知识写下来</strong>，才能让 Agent 使用。</p><p>OpenAI 每周花 20% 的时间做代码清理，后来他们把标准编码进 Harness 本身才解决了这个问题。Anthropic 的 Nicholas Carlini 做过 16 个并行 Agent 构建 C 编译器的实验，他的原话是：&quot;我大部分精力都花在设计 Claude 周围的环境上。&quot;</p><h3 id="为什么上了-agent-反而更乱了" tabindex="-1">为什么上了 Agent 反而更乱了？ <a class="header-anchor" href="#为什么上了-agent-反而更乱了" aria-label="Permalink to &quot;为什么上了 Agent 反而更乱了？&quot;">​</a></h3><p>文档、自动化测试、成文的架构决策——这些一直都是对的。过去 30 年几乎所有工程师都在推荐这些事，很多人跳过是因为代价来得很慢。</p><p>Agent 工程把这种代价放大到了极端：</p><table tabindex="0"><thead><tr><th style="text-align:left;">跳过的实践</th><th style="text-align:left;">传统代价</th><th style="text-align:left;">Agent 时代的代价</th></tr></thead><tbody><tr><td style="text-align:left;">文档</td><td style="text-align:left;">一个 PR 里忽略约定</td><td style="text-align:left;">机器速度、全天候、每一个 PR 都忽略约定</td></tr><tr><td style="text-align:left;">测试</td><td style="text-align:left;">偶尔漏检 bug</td><td style="text-align:left;">反馈回路根本闭合不起来</td></tr><tr><td style="text-align:left;">架构约束</td><td style="text-align:left;">架构缓慢漂移</td><td style="text-align:left;">漂移速度比你修补的速度还快</td></tr></tbody></table><p>更糟的陷阱：如果 Agent 根本不知道&quot;整洁&quot;长什么样，你甚至没法用 Agent 来清理它制造出来的混乱。没有校准，制造问题的机器也同样无法解决问题。</p><blockquote><p><strong>实践本身没有变。变得难以承受的是忽视这些实践的代价。</strong></p></blockquote><h3 id="人在-agent-时代的位置" tabindex="-1">人在 Agent 时代的位置 <a class="header-anchor" href="#人在-agent-时代的位置" aria-label="Permalink to &quot;人在 Agent 时代的位置&quot;">​</a></h3><p>验证一个答案对不对，比生成一个正确答案要容易得多。这个规律在 LLM 上也被实验证实了。所以你不需要在实现速度上跟机器竞争。</p><p>你需要专注在评估这一侧：<strong>定义</strong>什么叫正确、<strong>识别</strong>输出哪里偏了、<strong>判断</strong>方向是否对路。</p><p>工程师不会消失，但工程师的工作会像前两次一样——再上移一层。设计 Watt 调速器的工人没有回去转阀门，不是因为他们不能，而是因为这样做不再有意义。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ol><li><strong>Harness = 操作系统</strong>——料理上下文、处理引导、预埋钩子、提供驱动；2026 年的核心定位是基础设施</li><li><strong>Build to Delete</strong>——Harness 代码注定被删，真正的价值是捕获崩溃数据（The Harness is the dataset）</li><li><strong>控制论闭环</strong>——输出影响输入、系统自己纠偏；每一次技术跃迁都是在某个层级上第一次成功闭环</li><li><strong>校准比闭环更重要</strong>——闭环是必要条件，校准是充分条件；必须把隐性知识显性化写进 Harness</li><li><strong>人再上移一层</strong>——不需要跟机器比实现速度，专注定义正确、识别偏差、判断方向</li></ol><hr><p><a href="./03-成本、自主与熵增.html">← 上一章：成本、自主与熵增</a> | <a href="./05-验证、工具与优化.html">下一章：验证、工具与优化 →</a></p>',25))])}const y=i(A,[["render",E]]);export{c as __pageData,y as default};
